// Extract notices/announcements from MSBTE page.
// Hash current content and compare with last run.

const html = $input.first().json || '';
const staticData = $getWorkflowStaticData('global');

// ─── Extract notice links and headings ────────────────────────────────────
const notices = [];

// Pattern 1: anchor tags that look like notices
const linkRegex = /<a[^>]+href=["']([^"']*)["'][^>]*>([^<]{10,200})<\/a>/gi;
let linkMatch;
while ((linkMatch = linkRegex.exec(html)) !== null) {
  const href = linkMatch[1];
  const text = linkMatch[2].replace(/\s+/g, ' ').trim();
  // Keep entries that look like notices (contain keywords or link to PDFs)
  if (
    text.length > 15 &&
    (
      /circular|notice|exam|result|timetable|schedule|notification|important|admit|hall ticket|merit|registration/i.test(text) ||
      href.includes('.pdf') ||
      href.includes('notification')
    )
  ) {
    notices.push({ text, href });
  }
}

// Deduplicate by text
const seen = new Set();
const uniqueNotices = notices.filter((n) => {
  if (seen.has(n.text)) return false;
  seen.add(n.text);
  return true;
}).slice(0, 15); // top 15

// ─── Hash the notice list ──────────────────────────────────────────────────
const noticeSignature = uniqueNotices.map((n) => n.text).join('|');

// Simple 32-bit hash
let hash = 0;
for (let i = 0; i < noticeSignature.length; i++) {
  const c = noticeSignature.charCodeAt(i);
  hash = (Math.imul(31, hash) + c) | 0;
}
const currentHash = String(hash);
const lastHash = staticData.lastNoticeHash || '';

if (currentHash === lastHash && lastHash !== '') {
  // No change
  return [];
}

// Changed — update stored hash
staticData.lastNoticeHash = currentHash;

// Find which notices are new (simple diff: ones not in previous text block)
const lastTexts = (staticData.lastNoticeTexts || '').split('||');
const newNotices = uniqueNotices.filter((n) => !lastTexts.includes(n.text));
staticData.lastNoticeTexts = uniqueNotices.map((n) => n.text).join('||');

return [{
  json: {
    changed: true,
    newNoticeCount: newNotices.length,
    newNotices,
    allNotices: uniqueNotices,
    totalFound: uniqueNotices.length
  }
}];

const item = $input.first().json;
const notices = item.newNotices.length > 0 ? item.newNotices : item.allNotices.slice(0, 5);
const header = item.newNotices.length > 0
  ? `📢 *${item.newNotices.length} new MSBTE notice(s)*`
  : `📋 *MSBTE page changed* (${item.totalFound} notices found)`;

const noticeLines = notices.map((n) => {
  const href = n.href.startsWith('http') ? n.href : `https://msbte.org.in${n.href}`;
  return `• [${n.text.slice(0, 80)}](${href})`;
}).join('\n');

const text = [
  header,
  ``,
  noticeLines,
  ``,
  `🔗 [View all notices](https://msbte.org.in/)`
].join('\n');

return [{ json: { text } }];
